proof fn phi_1_lemma_entry_sizes_aligned_external_body(arch: Arch, i: nat, j: nat)
    requires
        arch.inv(),
        i <= j,
        j < arch.layers.len(),
    ensures
        aligned(arch.entry_size(i), arch.entry_size(j)),
{
    arch.lemma_entry_sizes_aligned(i, j);
}

proof fn phi_2_self_aligned(arch: Arch, i: nat)
    requires
        arch.inv(),
        i < arch.layers.len(),
    ensures
        aligned(arch.entry_size(i), arch.entry_size(i)),
{
    arch.lemma_entry_sizes_aligned(i, i);
}

proof fn phi_3_aligned_auto_instantiation(arch: Arch)
    requires
        arch.inv(),
        arch.layers.len() >= 2,
    ensures
        aligned(arch.entry_size(0), arch.entry_size(1)),
{
    arch.lemma_entry_sizes_aligned_auto();
}

proof fn phi_4_adjacent_layers_divisible(arch: Arch, i: nat)
    requires
        arch.inv(),
        i + 1 < arch.layers.len(),
    ensures
        arch.entry_size(i) % arch.entry_size(i + 1) == 0,
{
    arch.lemma_entry_sizes_aligned(i, i + 1);
}
